import{c as t,Q as o,j as d,m as a}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"@muhaven/mcp — tool catalog","description":"The 25 tools across read · position · cash · policy · issuer · governance.","frontmatter":{"title":"@muhaven/mcp — tool catalog","description":"The 25 tools across read · position · cash · policy · issuer · governance."},"headers":[],"relativePath":"mcp/tools.md","filePath":"mcp/tools.md","lastUpdated":1780199385000}'),r={name:"mcp/tools.md"};function s(n,e,c,i,h,l){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="mcp-tool-catalog" tabindex="-1">MCP tool catalog <a class="header-anchor" href="#mcp-tool-catalog" aria-label="Permalink to &quot;MCP tool catalog&quot;">​</a></h1><p><code>@muhaven/mcp</code> exposes <strong>25 tools</strong> organized into six groups. Each tool ships with a strict-Zod input schema, an output schema, and a SHA-256 description hash pinned at build time (re-verified on every server startup; drift exits with <code>EX_CONFIG</code>).</p><p><strong>Scope</strong> tells you which JWT claim is required (set when you authorized the device). <strong>Tier-gate</strong> tells you whether the action is blocked when your tiered-autonomy state is <code>Paused</code>.</p><h2 id="muhaven-read-—-read-only-8-tools" tabindex="-1"><code>muhaven.read.*</code> — read-only (8 tools) <a class="header-anchor" href="#muhaven-read-—-read-only-8-tools" aria-label="Permalink to &quot;`muhaven.read.*` — read-only (8 tools)&quot;">​</a></h2><p>Always available. No signing required.</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.read.portfolio</code></td><td>Aggregate portfolio summary (token list, ebool flags). <strong>Never</strong> returns encrypted balance handles or cleartext amounts.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.yields</code></td><td>Per-token plaintext yield history (epoch index, distribution timestamp, per-share USD).</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.distribution</code></td><td>Distribution status for a (tokenAddress, epochId) tuple — funded / settled / claim-window.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.tokens</code></td><td>RWA tokens you currently hold (address, symbol, decimals, asset class, status).</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.audit</code></td><td>Your tiered-autonomy audit log (cursor-paginated). User-self only.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.activity</code></td><td>On-chain activity feed (buys / sells / wraps / unwraps / yield claims / transfers). Each row carries token address, tx hash, block timestamp, and event type — amounts are encrypted handles only. Use to verify a dashboard action settled after position.buy / position.sell / cash.wrap.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.protection_coverage</code></td><td>DefaultProtection coverage state for a token (on-chain proxy state). Returns <code>not_deployed</code> when the P11.A contract is not yet on-chain.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.read.kyc_attestation</code></td><td>KYC attestation registry status (informational). Returns <code>not_deployed</code> when the P11.C registry is not yet on-chain.</td><td><code>mcp.read.*</code></td><td>none</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Read tools are intentionally non-auditing by design</p><p>We do <strong>not</strong> log every &quot;user looked at portfolio&quot; call. Only <code>position.*</code> / <code>policy.*</code> / <code>issuer.*</code> / <code>governance.*</code> propose+commit events emit audit rows. This is a privacy choice; the trade-off is forensic — see <a href="/policy/audit-log">Audit log</a>.</p></div><h2 id="muhaven-position-—-propose-only-trades-4-tools" tabindex="-1"><code>muhaven.position.*</code> — propose-only trades (4 tools) <a class="header-anchor" href="#muhaven-position-—-propose-only-trades-4-tools" aria-label="Permalink to &quot;`muhaven.position.*` — propose-only trades (4 tools)&quot;">​</a></h2><p>All position tools return an <strong>unsigned UserOp envelope plus a broker signature</strong>. They never auto-submit. The host LLM must present the envelope to you for explicit confirmation.</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.position.buy</code></td><td>Propose a Subscription buy of N shares of token T using mhUSDC.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.position.sell</code></td><td>Propose a redemption-queue sell.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.position.claim</code></td><td>Propose a yield claim for one or more (token, epoch) tuples.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.position.rebalance</code></td><td>Propose a multi-leg atomic rebalance. Returns the descriptor; ceremony completes from a browser surface.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr></tbody></table><h2 id="muhaven-cash-—-confidential-cash-2-tools" tabindex="-1"><code>muhaven.cash.*</code> — confidential cash (2 tools) <a class="header-anchor" href="#muhaven-cash-—-confidential-cash-2-tools" aria-label="Permalink to &quot;`muhaven.cash.*` — confidential cash (2 tools)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.cash.wrap</code></td><td>Prepare a USDC → mhUSDC wrap. Returns a dashboard deep-link (muhaven.app/cash?amount=...&amp;from=mcp) with the amount pre-filled. Input <code>amountUsdc</code> is human-readable (&quot;100&quot; = $100). Verify settlement via muhaven.read.activity (a new &quot;wrap&quot; row).</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.cash.unwrap</code></td><td>Prepare an mhUSDC → USDC withdrawal (inverse of cash.wrap). Returns a dashboard deep-link that lands on the Withdraw form. Two-phase async: burn mhUSDC + request decrypt (~30–60s), then claim USDC from the on-chain reserve. The dashboard drives both phases; this tool never submits either.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr></tbody></table><h2 id="muhaven-policy-—-tiered-autonomy-state-4-tools" tabindex="-1"><code>muhaven.policy.*</code> — tiered-autonomy state (4 tools) <a class="header-anchor" href="#muhaven-policy-—-tiered-autonomy-state-4-tools" aria-label="Permalink to &quot;`muhaven.policy.*` — tiered-autonomy state (4 tools)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.policy.set_tier</code></td><td>Request or commit a tier transition. Tiers: Advisory / Confirm-per-action / Policy-bound / Paused.</td><td><code>mcp.propose.*</code></td><td>special — Paused → any requires the dashboard ceremony</td></tr><tr><td><code>muhaven.policy.pause</code></td><td>Activate the <code>/pause</code> kill-switch. Uninstalls the on-chain validator in ≤1 Arb block.</td><td><code>mcp.propose.*</code></td><td>idempotent (always allowed)</td></tr><tr><td><code>muhaven.policy.audit_export</code></td><td>Drain your audit log to a downloadable JSON.</td><td><code>mcp.read.*</code></td><td>none</td></tr><tr><td><code>muhaven.policy.session_key_status</code></td><td>Inspect the ZeroDev session-key state — install fingerprint, expiration, scope.</td><td><code>mcp.read.*</code></td><td>none</td></tr></tbody></table><h2 id="muhaven-issuer-—-issuer-only-5-tools" tabindex="-1"><code>muhaven.issuer.*</code> — issuer-only (5 tools) <a class="header-anchor" href="#muhaven-issuer-—-issuer-only-5-tools" aria-label="Permalink to &quot;`muhaven.issuer.*` — issuer-only (5 tools)&quot;">​</a></h2><p>Backend routes guard these with <code>withRole(&#39;issuer&#39;) &amp;&amp; issuerStatus === &#39;approved&#39;</code>. An investor-roled JWT or an unapproved issuer-roled JWT gets a 403 <code>NOT_APPROVED_ISSUER</code>.</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.issuer.distribute_yield</code></td><td>Propose <code>startDistribution → batchCreate → fundFrom</code> UserOp triple for an epoch.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.issuer.kyc_add</code></td><td>Propose adding an investor wallet to the ERC-3643 whitelist.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.issuer.kyc_remove</code></td><td>Propose removing a wallet from the whitelist.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.issuer.unpause_token</code></td><td>Propose <code>setNAVAndUnpause</code> for a freshly-deployed token.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.issuer.audit_query</code></td><td>Read your own issuer-side tiered-autonomy audit log.</td><td><code>mcp.read.*</code></td><td>none</td></tr></tbody></table><h2 id="muhaven-governance-—-encrypted-governance-2-tools" tabindex="-1"><code>muhaven.governance.*</code> — encrypted governance (2 tools) <a class="header-anchor" href="#muhaven-governance-—-encrypted-governance-2-tools" aria-label="Permalink to &quot;`muhaven.governance.*` — encrypted governance (2 tools)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th><th>Scope</th><th>Tier-gate</th></tr></thead><tbody><tr><td><code>muhaven.governance.propose</code></td><td>Propose an EncryptedGovernance vote. Supports <code>proposalType=0</code> (TRIGGER_PROTECTION).</td><td><code>mcp.propose.*</code></td><td>yes</td></tr><tr><td><code>muhaven.governance.cast_vote</code></td><td>Cast an encrypted vote on an open proposal. Backend enforces voter eligibility.</td><td><code>mcp.propose.*</code></td><td>yes</td></tr></tbody></table><h2 id="read-only-mode" tabindex="-1">Read-only mode <a class="header-anchor" href="#read-only-mode" aria-label="Permalink to &quot;Read-only mode&quot;">​</a></h2><p>Set <code>MUHAVEN_READ_ONLY=true</code> in the broker env to register <strong>only the eight <code>muhaven.read.*</code> tools</strong>. The position / cash / policy / issuer / governance groups are not even surfaced to the host LLM — defense in depth for a &quot;give my LLM read-only visibility&quot; deployment.</p><p>See <a href="/mcp/read-only-mode">Read-only mode</a>.</p><h2 id="tool-description-hashes" tabindex="-1">Tool description hashes <a class="header-anchor" href="#tool-description-hashes" aria-label="Permalink to &quot;Tool description hashes&quot;">​</a></h2><p>Every tool description is hashed with SHA-256 at build time into <code>packages/mcp/tool-hashes.json</code>. The MCP server re-verifies on startup; any drift exits with code 70 (<code>EX_CONFIG</code>). This is the <a href="https://github.com/anthropics/mcp-context-protector" target="_blank" rel="noreferrer"><code>mcp-context-protector</code> pattern</a> — guards against post-install MCPoison-style description swaps.</p><p>If an <code>npm update</code> ever changes a tool&#39;s description, your install will refuse to start until you re-verify and update the pin. That&#39;s intentional: the description is part of the security contract.</p><h2 id="why-no-muhaven-checkout-mcp-tools" tabindex="-1">Why no <code>muhaven.checkout.*</code> MCP tools? <a class="header-anchor" href="#why-no-muhaven-checkout-mcp-tools" aria-label="Permalink to &quot;Why no `muhaven.checkout.*` MCP tools?&quot;">​</a></h2><p>The hosted-checkout surface creates URLs that buyers redeem in a browser. It&#39;s not LLM-callable end-to-end: an LLM can mint a checkout link (via HavenBot&#39;s <code>create_checkout</code> tool), but the buyer-side flow needs a real browser for the passkey ceremony.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/mcp/first-chat">First chat</a> — walk through your first portfolio query.</li><li><a href="/mcp/playbook">Playbook</a> — scenarios that span MuHaven plus other MCP servers.</li><li><a href="/mcp/read-only-mode">Read-only mode</a> — restrict your install.</li><li><a href="/reference/tool-catalog">Tool catalog (all surfaces)</a> — cross-surface comparison.</li></ul>',29)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
